import Foundation
import SwiftUI
import PocketGrisCore

/// Observable view model bridging Core behavior to SwiftUI
@MainActor
final class CreatureViewModel: ObservableObject {
    // Position from behavior (target position)
    @Published var position: Position = .zero

    // Smoothly interpolated display position for rendering
    @Published var displayPosition: Position = .zero

    @Published var currentFramePath: String?
    @Published var isVisible: Bool = false
    @Published var flipHorizontal: Bool = false
    @Published var opacity: Double = 1.0

    private let creature: Creature
    private let behavior: any Behavior
    private var state: BehaviorState
    private let spriteLoader: SpriteLoader
    private let screenBounds: ScreenRect
    private let random: RandomSource
    private var timeSource: TimeSource
    private let windowTracker: WindowTracker?

    // Animation state for sliding
    private var slideStartPosition: Position = .zero
    private var slideTargetPosition: Position = .zero
    private var slideProgress: Double = 1.0  // 1.0 = complete
    private var slideDuration: TimeInterval = 0.3
    private let slideSpeed: Double = 200.0  // pixels per second for normal movement

    // Offscreen offset for hiding sprite at edge
    private let hideOffset: Double = 80

    var onComplete: (() -> Void)?

    init(
        creature: Creature,
        behaviorType: BehaviorType,
        screenBounds: ScreenRect,
        spriteLoader: SpriteLoader,
        timeSource: TimeSource = SystemTimeSource(),
        random: RandomSource = SystemRandomSource(),
        windowTracker: WindowTracker? = nil
    ) {
        self.creature = creature
        self.behavior = BehaviorRegistry.shared.behavior(for: behaviorType) ?? PeekBehavior()
        self.screenBounds = screenBounds
        self.spriteLoader = spriteLoader
        self.timeSource = timeSource
        self.random = random
        self.windowTracker = windowTracker

        // Initialize state
        let windowFrames = windowTracker?.getWindowFrames() ?? []
        let context = BehaviorContext(
            creature: creature,
            screenBounds: screenBounds,
            currentTime: timeSource.now,
            windowFrames: windowFrames
        )
        self.state = behavior.start(context: context, random: random)

        // Initial position and flip based on edge
        position = state.position
        if let edge = state.edge {
            flipHorizontal = (edge == .right)
            // Start offscreen for sliding entrance
            displayPosition = offscreenPosition(for: edge, target: state.position)
        } else {
            displayPosition = state.position
        }

        updateFramePath()
        preloadSprites()
    }

    func start() {
        isVisible = true
        opacity = 1.0

        // Start sliding in from edge
        if let edge = state.edge {
            startSlide(
                from: offscreenPosition(for: edge, target: position),
                to: position,
                duration: 0.4
            )
        }
    }

    func cancel() {
        let events = behavior.cancel(state: &state)
        handleEvents(events)
    }

    func update(deltaTime: TimeInterval) {
        let windowFrames = windowTracker?.getWindowFrames() ?? []
        let context = BehaviorContext(
            creature: creature,
            screenBounds: screenBounds,
            currentTime: timeSource.now,
            cursorPosition: getCurrentCursorPosition(),
            windowFrames: windowFrames
        )

        let events = behavior.update(state: &state, context: context, deltaTime: deltaTime)
        handleEvents(events)

        // Update target position from behavior
        let newPosition = state.position
        if newPosition != position {
            // Update flip direction based on movement
            if newPosition.x > position.x {
                flipHorizontal = false  // Moving right, face right
            } else if newPosition.x < position.x {
                flipHorizontal = true   // Moving left, face left
            }
            position = newPosition
        }

        // Update slide animation
        updateSlide(deltaTime: deltaTime)

        // Update animation frame
        if events.contains(where: {
            if case .animationFrameChanged = $0 { return true }
            return false
        }) {
            updateFramePath()
        }
    }

    private func handleEvents(_ events: [BehaviorEvent]) {
        for event in events {
            switch event {
            case .completed, .cancelled:
                isVisible = false
                onComplete?()

            case .phaseChanged(let phase):
                handlePhaseChange(phase)
                updateFramePath()

            case .positionChanged(let pos):
                position = pos

            case .animationFrameChanged:
                break

            case .started:
                break
            }
        }
    }

    private func handlePhaseChange(_ phase: BehaviorPhase) {
        switch phase {
        case .exit:
            // Start sliding back offscreen
            if let edge = state.edge {
                let target = offscreenPosition(for: edge, target: displayPosition)
                startSlide(from: displayPosition, to: target, duration: 0.5)
            }

        case .perform:
            // Ensure we're at the target position
            if slideProgress >= 1.0 {
                displayPosition = position
            }

        default:
            break
        }
    }

    // MARK: - Sliding Animation

    private func startSlide(from: Position, to: Position, duration: TimeInterval) {
        slideStartPosition = from
        slideTargetPosition = to
        slideProgress = 0.0
        slideDuration = duration
    }

    private func updateSlide(deltaTime: TimeInterval) {
        // If in perform phase and behavior updates position continuously, follow it
        if state.phase == .perform && slideProgress >= 1.0 {
            // Smoothly follow the behavior's position
            let followSpeed = 8.0  // How fast to catch up
            let dx = position.x - displayPosition.x
            let dy = position.y - displayPosition.y

            // Only interpolate if there's a significant difference
            if abs(dx) > 0.5 || abs(dy) > 0.5 {
                displayPosition = Position(
                    x: displayPosition.x + dx * min(followSpeed * deltaTime, 1.0),
                    y: displayPosition.y + dy * min(followSpeed * deltaTime, 1.0)
                )
            } else {
                displayPosition = position
            }
            return
        }

        guard slideProgress < 1.0 else {
            displayPosition = slideTargetPosition
            return
        }

        slideProgress += deltaTime / slideDuration
        slideProgress = min(slideProgress, 1.0)

        // Ease out cubic for smooth deceleration
        let t = slideProgress
        let eased = 1.0 - pow(1.0 - t, 3)

        displayPosition = Position(
            x: slideStartPosition.x + (slideTargetPosition.x - slideStartPosition.x) * eased,
            y: slideStartPosition.y + (slideTargetPosition.y - slideStartPosition.y) * eased
        )
    }

    private func offscreenPosition(for edge: ScreenEdge, target: Position) -> Position {
        switch edge {
        case .left:
            return Position(x: target.x - hideOffset, y: target.y)
        case .right:
            return Position(x: target.x + hideOffset, y: target.y)
        case .top:
            return Position(x: target.x, y: target.y - hideOffset)
        case .bottom:
            return Position(x: target.x, y: target.y + hideOffset)
        }
    }

    // MARK: - Sprites

    private func updateFramePath() {
        guard let anim = state.animation else {
            currentFramePath = nil
            return
        }

        currentFramePath = spriteLoader.framePath(
            creature: creature.id,
            animation: anim.animation.name,
            frame: anim.currentFrame
        )
    }

    private func preloadSprites() {
        // Preload all animation frames for this creature in background
        let creatureId = creature.id
        let animations = Array(creature.animations.keys)
        let loader = spriteLoader

        DispatchQueue.global(qos: .userInitiated).async {
            ImageCache.shared.preloadCreature(
                id: creatureId,
                animations: animations,
                spriteLoader: loader
            )
        }
    }

    // MARK: - Input

    private func getCurrentCursorPosition() -> Position? {
        let mouseLocation = NSEvent.mouseLocation
        // Convert from bottom-left to top-left coordinate system
        guard let screen = NSScreen.main else { return nil }
        let y = screen.frame.height - mouseLocation.y
        return Position(x: mouseLocation.x, y: y)
    }
}

import AppKit
import PocketGrisCore

final class AppDelegate: NSObject, NSApplicationDelegate {

    private var statusItem: NSStatusItem!
    private var creatureWindow: CreatureWindow?
    private let spriteLoader = SpriteLoader()
    private let scheduler = BehaviorScheduler()
    private let ipcService = IPCService()
    private let windowTracker = AccessibilityWindowTracker()
    private var isEnabled = true

    func applicationDidFinishLaunching(_ notification: Notification) {
        setupMenuBar()
        setupIPC()
        loadCreatures()
        startScheduler()
    }

    func applicationWillTerminate(_ notification: Notification) {
        ipcService.stopListening()
        ipcService.markGUIRunning(false)
        scheduler.stop()
    }

    // MARK: - Menu Bar

    private func setupMenuBar() {
        statusItem = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)

        if let button = statusItem.button {
            button.image = NSImage(systemSymbolName: "pawprint.fill", accessibilityDescription: "Pocket Gris")
            button.image?.isTemplate = true
        }

        let menu = NSMenu()

        menu.addItem(NSMenuItem(title: "Trigger Now", action: #selector(triggerNow), keyEquivalent: "t"))
        menu.addItem(NSMenuItem.separator())

        let enableItem = NSMenuItem(title: "Enabled", action: #selector(toggleEnabled), keyEquivalent: "e")
        enableItem.state = isEnabled ? .on : .off
        menu.addItem(enableItem)

        menu.addItem(NSMenuItem.separator())
        menu.addItem(NSMenuItem(title: "Settings...", action: #selector(openSettings), keyEquivalent: ","))
        menu.addItem(NSMenuItem.separator())
        menu.addItem(NSMenuItem(title: "Quit", action: #selector(quit), keyEquivalent: "q"))

        statusItem.menu = menu
    }

    @objc private func triggerNow() {
        scheduler.triggerNow()
    }

    @objc private func toggleEnabled() {
        isEnabled.toggle()
        updateMenuState()

        var settings = Settings.load()
        settings.enabled = isEnabled
        try? settings.save()
        scheduler.updateSettings(settings)
    }

    @objc private func openSettings() {
        // TODO: Settings window
        print("Settings not yet implemented")
    }

    @objc private func quit() {
        NSApp.terminate(nil)
    }

    private func updateMenuState() {
        guard let menu = statusItem.menu else { return }
        for item in menu.items where item.action == #selector(toggleEnabled) {
            item.state = isEnabled ? .on : .off
        }
    }

    // MARK: - IPC

    private func setupIPC() {
        ipcService.markGUIRunning(true)
        ipcService.startListening { [weak self] message in
            self?.handleIPCMessage(message) ?? IPCResponse(success: false, message: "App not ready")
        }
    }

    private func handleIPCMessage(_ message: IPCMessage) -> IPCResponse {
        switch message.command {
        case .trigger:
            DispatchQueue.main.async { [weak self] in
                if let creatureId = message.creature,
                   let creature = self?.spriteLoader.creature(id: creatureId) {
                    let behavior = message.behavior.flatMap { BehaviorType(rawValue: $0) }
                    self?.scheduler.triggerNow(creature: creature, behavior: behavior)
                } else {
                    self?.scheduler.triggerNow()
                }
            }
            return IPCResponse(success: true, message: "Triggered")

        case .enable:
            DispatchQueue.main.async { [weak self] in
                self?.isEnabled = true
                self?.updateMenuState()
                var settings = Settings.load()
                settings.enabled = true
                try? settings.save()
                self?.scheduler.updateSettings(settings)
            }
            return IPCResponse(success: true, message: "Enabled")

        case .disable:
            DispatchQueue.main.async { [weak self] in
                self?.isEnabled = false
                self?.updateMenuState()
                var settings = Settings.load()
                settings.enabled = false
                try? settings.save()
                self?.scheduler.updateSettings(settings)
            }
            return IPCResponse(success: true, message: "Disabled")

        case .cancel:
            DispatchQueue.main.async { [weak self] in
                self?.creatureWindow?.close()
                self?.creatureWindow = nil
            }
            return IPCResponse(success: true, message: "Cancelled")

        case .status:
            let creatures = spriteLoader.allCreatures()
            return IPCResponse(
                success: true,
                message: nil,
                data: [
                    "enabled": String(isEnabled),
                    "creatures": String(creatures.count),
                    "windowVisible": String(creatureWindow != nil)
                ]
            )
        }
    }

    // MARK: - Creatures

    private func loadCreatures() {
        let creatures = spriteLoader.loadAllCreatures()
        scheduler.updateCreatures(creatures)
        print("Loaded \(creatures.count) creatures")

        if creatures.isEmpty {
            print("No creatures found in Resources/Sprites/")
            print("Add sprite folders with creature.json manifests")
        }
    }

    private func startScheduler() {
        let settings = Settings.load()
        scheduler.updateSettings(settings)
        isEnabled = settings.enabled

        scheduler.setTriggerHandler { [weak self] creature, behaviorType in
            self?.showCreature(creature, behavior: behaviorType)
        }

        scheduler.start()
    }

    private func showCreature(_ creature: Creature, behavior behaviorType: BehaviorType) {
        guard isEnabled else { return }

        // Close any existing window
        creatureWindow?.close()

        // Create and show new creature window
        let window = CreatureWindow()
        window.show(
            creature: creature,
            behavior: behaviorType,
            spriteLoader: spriteLoader,
            windowTracker: windowTracker
        ) { [weak self] in
            self?.creatureWindow = nil
        }
        creatureWindow = window
    }
}

import Foundation

/// Peek behavior: appear at edge, peek, retreat
public struct PeekBehavior: Behavior {
    public let type = BehaviorType.peek
    public let requiredAnimations = ["peek-left", "retreat-left"]

    public init() {}

    public func start(context: BehaviorContext, random: RandomSource) -> BehaviorState {
        // Pick a random edge
        let edges: [ScreenEdge] = [.left, .right, .top, .bottom]
        let edge = edges[random.int(in: 0..<edges.count)]

        // Calculate position at edge
        let position = calculateEdgePosition(edge: edge, bounds: context.screenBounds, random: random)

        // Get peek duration from personality
        let duration = random.double(in: context.creature.personality.peekDurationRange)

        // Get animation (try directional first)
        let animName = animationName(for: edge, action: "peek")
        let anim = context.creature.animation(named: animName)
            ?? context.creature.animation(named: "peek-left")

        var state = BehaviorState(
            phase: .enter,
            position: position,
            animation: anim.map { AnimationState(animation: $0) },
            edge: edge,
            startTime: context.currentTime,
            duration: duration
        )
        state.metadata["peekDuration"] = String(duration)

        return state
    }

    public func update(
        state: inout BehaviorState,
        context: BehaviorContext,
        deltaTime: TimeInterval
    ) -> [BehaviorEvent] {
        var events: [BehaviorEvent] = []

        // Update animation
        if state.animation?.advance(by: deltaTime) == true {
            events.append(.animationFrameChanged(state.animation!.currentFrame))
        }

        let elapsed = context.currentTime - state.startTime

        switch state.phase {
        case .idle:
            break

        case .enter:
            // Enter phase complete when animation finishes or after brief delay
            if state.animation?.isComplete == true || elapsed > 0.5 {
                state.phase = .perform
                events.append(.phaseChanged(.perform))
                state.startTime = context.currentTime

                // Check for cursor proximity - might flee
                if let cursor = context.cursorPosition {
                    let distance = state.position.distance(to: cursor)
                    if distance < 100 && context.creature.personality.cursorSensitivity > 0.5 {
                        // Skip to exit
                        state.phase = .exit
                        events.append(.phaseChanged(.exit))
                        state.startTime = context.currentTime
                        transitionToRetreat(state: &state, context: context)
                    }
                }
            }

        case .perform:
            // Wait for peek duration
            let peekDuration = Double(state.metadata["peekDuration"] ?? "3") ?? 3.0
            if elapsed >= peekDuration {
                state.phase = .exit
                events.append(.phaseChanged(.exit))
                state.startTime = context.currentTime
                transitionToRetreat(state: &state, context: context)
            }

            // Check cursor - might flee early
            if let cursor = context.cursorPosition {
                let distance = state.position.distance(to: cursor)
                let fleeThreshold = 80.0 * (1.0 - context.creature.personality.cursorSensitivity)
                if distance < fleeThreshold {
                    state.phase = .exit
                    events.append(.phaseChanged(.exit))
                    state.startTime = context.currentTime
                    transitionToRetreat(state: &state, context: context)
                }
            }

        case .exit:
            // Exit complete when retreat animation finishes
            if state.animation?.isComplete == true || elapsed > 1.0 {
                state.phase = .complete
                events.append(.phaseChanged(.complete))
                events.append(.completed)
            }

        case .complete:
            break
        }

        return events
    }

    public func cancel(state: inout BehaviorState) -> [BehaviorEvent] {
        if state.phase != .complete {
            state.phase = .complete
            return [.cancelled]
        }
        return []
    }

    // MARK: - Helpers

    private func calculateEdgePosition(edge: ScreenEdge, bounds: ScreenRect, random: RandomSource) -> Position {
        switch edge {
        case .left:
            let y = random.double(in: bounds.minY + 50...bounds.maxY - 50)
            return Position(x: bounds.minX, y: y)
        case .right:
            let y = random.double(in: bounds.minY + 50...bounds.maxY - 50)
            return Position(x: bounds.maxX, y: y)
        case .top:
            let x = random.double(in: bounds.minX + 50...bounds.maxX - 50)
            return Position(x: x, y: bounds.minY)
        case .bottom:
            let x = random.double(in: bounds.minX + 50...bounds.maxX - 50)
            return Position(x: x, y: bounds.maxY)
        }
    }

    private func animationName(for edge: ScreenEdge, action: String) -> String {
        switch edge {
        case .left: return "\(action)-left"
        case .right: return "\(action)-right"
        case .top: return "\(action)-top"
        case .bottom: return "\(action)-bottom"
        }
    }

    private func transitionToRetreat(state: inout BehaviorState, context: BehaviorContext) {
        guard let edge = state.edge else { return }
        let animName = animationName(for: edge, action: "retreat")
        if let anim = context.creature.animation(named: animName)
            ?? context.creature.animation(named: "retreat-left") {
            state.animation = AnimationState(animation: anim)
        }
    }
}

import Foundation

/// Traverse behavior: walk across screen from one edge to the opposite
public struct TraverseBehavior: Behavior {
    public let type = BehaviorType.traverse
    public let requiredAnimations = ["walk-left", "idle"]

    private let calculator = PositionCalculator()

    public init() {}

    public func start(context: BehaviorContext, random: RandomSource) -> BehaviorState {
        // Pick random horizontal direction (left-to-right or right-to-left)
        let startEdge: ScreenEdge = random.bool() ? .left : .right
        let endEdge: ScreenEdge = startEdge == .left ? .right : .left

        // Calculate Y position (consistent across the traverse)
        let bounds = context.screenBounds
        let margin: Double = 100
        let y = random.double(in: (bounds.minY + margin)...(bounds.maxY - margin))

        // Calculate positions
        let startX = startEdge == .left ? bounds.minX - 50 : bounds.maxX + 50
        let endX = endEdge == .left ? bounds.minX - 50 : bounds.maxX + 50

        let startPosition = Position(x: startX, y: y)

        // Get walk animation (fall back to idle if no directional walk)
        let walkAnim = walkAnimation(direction: endEdge, creature: context.creature)

        // Calculate traverse speed and duration from personality
        let speed = context.creature.personality.traverseSpeed
        let distance = abs(endX - startX)
        let duration = distance / speed

        var state = BehaviorState(
            phase: .enter,
            position: startPosition,
            animation: AnimationState(animation: walkAnim),
            edge: startEdge,
            startTime: context.currentTime,
            duration: duration
        )

        // Store path info in metadata
        state.metadata["startX"] = String(startX)
        state.metadata["endX"] = String(endX)
        state.metadata["y"] = String(y)
        state.metadata["startEdge"] = startEdge.rawValue
        state.metadata["endEdge"] = endEdge.rawValue
        state.metadata["speed"] = String(speed)

        return state
    }

    public func update(
        state: inout BehaviorState,
        context: BehaviorContext,
        deltaTime: TimeInterval
    ) -> [BehaviorEvent] {
        var events: [BehaviorEvent] = []

        // Update animation
        if state.animation?.advance(by: deltaTime) == true {
            events.append(.animationFrameChanged(state.animation!.currentFrame))
        }

        let elapsed = context.currentTime - state.startTime

        switch state.phase {
        case .idle:
            break

        case .enter:
            // Short enter phase - just start moving
            if elapsed > 0.1 {
                state.phase = .perform
                events.append(.phaseChanged(.perform))
                state.startTime = context.currentTime
            }

        case .perform:
            // Move across screen
            guard let startX = Double(state.metadata["startX"] ?? ""),
                  let endX = Double(state.metadata["endX"] ?? ""),
                  let y = Double(state.metadata["y"] ?? ""),
                  let speed = Double(state.metadata["speed"] ?? "") else {
                state.phase = .complete
                events.append(.completed)
                return events
            }

            // Calculate current position based on elapsed time and speed
            let distance = speed * elapsed
            let direction: Double = endX > startX ? 1.0 : -1.0
            let currentX = startX + (distance * direction)

            // Check if reached destination
            let reachedEnd = (direction > 0 && currentX >= endX) || (direction < 0 && currentX <= endX)

            if reachedEnd {
                state.position = Position(x: endX, y: y)
                events.append(.positionChanged(state.position))
                state.phase = .exit
                events.append(.phaseChanged(.exit))
                state.startTime = context.currentTime
            } else {
                let newPosition = Position(x: currentX, y: y)
                if newPosition != state.position {
                    state.position = newPosition
                    events.append(.positionChanged(newPosition))
                }
            }

            // Check for cursor proximity - might speed up or slow down
            if let cursor = context.cursorPosition {
                let distance = state.position.distance(to: cursor)
                let sensitivity = context.creature.personality.cursorSensitivity
                if distance < 150 && sensitivity > 0.3 {
                    // Speed boost when cursor is near
                    let boost = 1.0 + (1.0 - distance / 150) * sensitivity
                    state.metadata["speed"] = String(speed * boost)
                }
            }

        case .exit:
            // Brief exit phase
            if elapsed > 0.3 {
                state.phase = .complete
                events.append(.phaseChanged(.complete))
                events.append(.completed)
            }

        case .complete:
            break
        }

        return events
    }

    public func cancel(state: inout BehaviorState) -> [BehaviorEvent] {
        if state.phase != .complete {
            state.phase = .complete
            return [.cancelled]
        }
        return []
    }

    // MARK: - Helpers

    private func walkAnimation(direction: ScreenEdge, creature: Creature) -> Animation {
        // Try directional walk first, then generic walk, then idle
        let directionName = direction == .left ? "walk-left" : "walk-right"

        if let anim = creature.animation(named: directionName) {
            return anim
        }
        if let anim = creature.animation(named: "walk") {
            return anim
        }
        // Fall back to idle
        return creature.animation(named: "idle") ?? Animation(name: "idle", frameCount: 1, fps: 1)
    }
}

// MARK: - Personality Extension

extension Personality {
    /// Speed in pixels per second for traverse behavior
    var traverseSpeed: Double {
        switch self {
        case .shy:
            return 80.0        // Slow, cautious
        case .curious:
            return 120.0       // Moderate pace
        case .mischievous:
            return 150.0       // Quick, unpredictable
        case .chaotic:
            return 180.0       // Fast, erratic
        }
    }
}

import Foundation

/// Climber behavior: creature climbs along window edges
/// - Appears on a random window edge
/// - Walks along the edge (horizontally on top/bottom, vertically on left/right)
/// - May transition to adjacent edge at corners
/// - Disappears after completing a climb or on cursor proximity
public struct ClimberBehavior: Behavior {
    public let type = BehaviorType.climber
    public let requiredAnimations = ["climb", "idle"]

    public init() {}

    public func start(context: BehaviorContext, random: RandomSource) -> BehaviorState {
        // Need at least one window to climb
        guard !context.windowFrames.isEmpty else {
            // No windows available - use fallback idle at screen edge
            return createFallbackState(context: context, random: random)
        }

        // Pick a random window
        let windowIndex = random.int(in: 0..<context.windowFrames.count)
        let window = context.windowFrames[windowIndex]

        // Pick a random starting edge
        let edges: [ScreenRect.WindowEdge] = [.top, .bottom, .left, .right]
        let startEdge = edges[random.int(in: 0..<edges.count)]

        // Get starting position on the edge
        let startPosition = window.randomPositionOnEdge(startEdge, random: random)

        // Determine climb direction (along the edge)
        let climbDirection = random.bool() // true = positive direction (right/down), false = negative (left/up)

        // Calculate end position (corner or opposite corner of edge)
        let endPosition = calculateEndPosition(
            window: window,
            edge: startEdge,
            direction: climbDirection
        )

        // Duration based on distance and personality
        let distance = startPosition.distance(to: endPosition)
        let speed = context.creature.personality.climbSpeed
        let duration = distance / speed

        // Get climb animation
        let animation = climbAnimation(for: startEdge, creature: context.creature)

        var state = BehaviorState(
            phase: .enter,
            position: startPosition,
            animation: AnimationState(animation: animation),
            edge: nil,  // Not using screen edge, using window edge
            startTime: context.currentTime,
            duration: duration
        )

        // Store metadata
        state.metadata["windowIndex"] = String(windowIndex)
        state.metadata["windowEdge"] = String(describing: startEdge)
        state.metadata["climbDirection"] = climbDirection ? "positive" : "negative"
        state.metadata["startX"] = String(startPosition.x)
        state.metadata["startY"] = String(startPosition.y)
        state.metadata["endX"] = String(endPosition.x)
        state.metadata["endY"] = String(endPosition.y)
        state.metadata["speed"] = String(speed)

        // Store original window frame for tracking movement
        state.metadata["windowX"] = String(window.x)
        state.metadata["windowY"] = String(window.y)
        state.metadata["windowWidth"] = String(window.width)
        state.metadata["windowHeight"] = String(window.height)

        return state
    }

    public func update(
        state: inout BehaviorState,
        context: BehaviorContext,
        deltaTime: TimeInterval
    ) -> [BehaviorEvent] {
        var events: [BehaviorEvent] = []

        // Update animation
        if state.animation?.advance(by: deltaTime) == true {
            events.append(.animationFrameChanged(state.animation!.currentFrame))
        }

        let elapsed = context.currentTime - state.startTime

        switch state.phase {
        case .idle:
            break

        case .enter:
            // Short appearance phase
            if elapsed > 0.2 {
                state.phase = .perform
                events.append(.phaseChanged(.perform))
                state.startTime = context.currentTime
            }

        case .perform:
            // Climb along the edge
            guard var startX = Double(state.metadata["startX"] ?? ""),
                  var startY = Double(state.metadata["startY"] ?? ""),
                  var endX = Double(state.metadata["endX"] ?? ""),
                  var endY = Double(state.metadata["endY"] ?? ""),
                  let speed = Double(state.metadata["speed"] ?? "") else {
                state.phase = .complete
                events.append(.completed)
                return events
            }

            // Track window movement
            if let windowIndex = Int(state.metadata["windowIndex"] ?? ""),
               let origWindowX = Double(state.metadata["windowX"] ?? ""),
               let origWindowY = Double(state.metadata["windowY"] ?? ""),
               windowIndex < context.windowFrames.count {
                let currentWindow = context.windowFrames[windowIndex]
                let deltaX = currentWindow.x - origWindowX
                let deltaY = currentWindow.y - origWindowY

                // If window moved, adjust our coordinates
                if abs(deltaX) > 0.5 || abs(deltaY) > 0.5 {
                    startX += deltaX
                    startY += deltaY
                    endX += deltaX
                    endY += deltaY

                    // Update stored metadata with new positions
                    state.metadata["startX"] = String(startX)
                    state.metadata["startY"] = String(startY)
                    state.metadata["endX"] = String(endX)
                    state.metadata["endY"] = String(endY)
                    state.metadata["windowX"] = String(currentWindow.x)
                    state.metadata["windowY"] = String(currentWindow.y)
                }
            }

            // Calculate progress based on time and speed
            let totalDistance = Position(x: startX, y: startY).distance(to: Position(x: endX, y: endY))
            let distanceTraveled = speed * elapsed
            let progress = min(distanceTraveled / totalDistance, 1.0)

            // Interpolate position
            let currentX = startX + (endX - startX) * progress
            let currentY = startY + (endY - startY) * progress
            let newPosition = Position(x: currentX, y: currentY)

            if newPosition != state.position {
                state.position = newPosition
                events.append(.positionChanged(newPosition))
            }

            // Check for cursor proximity - flee if too close
            if let cursor = context.cursorPosition {
                let distance = state.position.distance(to: cursor)
                let sensitivity = context.creature.personality.cursorSensitivity
                let fleeThreshold = 100.0 * sensitivity

                if distance < fleeThreshold && sensitivity > 0.3 {
                    state.phase = .exit
                    events.append(.phaseChanged(.exit))
                    state.startTime = context.currentTime
                    return events
                }
            }

            // Check if completed climb
            if progress >= 1.0 {
                state.position = Position(x: endX, y: endY)
                events.append(.positionChanged(state.position))
                state.phase = .exit
                events.append(.phaseChanged(.exit))
                state.startTime = context.currentTime
            }

        case .exit:
            // Brief exit phase
            if elapsed > 0.3 {
                state.phase = .complete
                events.append(.phaseChanged(.complete))
                events.append(.completed)
            }

        case .complete:
            break
        }

        return events
    }

    public func cancel(state: inout BehaviorState) -> [BehaviorEvent] {
        if state.phase != .complete {
            state.phase = .complete
            return [.cancelled]
        }
        return []
    }

    // MARK: - Helpers

    private func createFallbackState(context: BehaviorContext, random: RandomSource) -> BehaviorState {
        // If no windows, fall back to simple stationary behavior at screen edge
        let bounds = context.screenBounds
        let position = Position(
            x: random.double(in: bounds.minX...bounds.maxX),
            y: bounds.maxY - 50  // Near bottom of screen
        )

        let animation = context.creature.animation(named: "idle")
            ?? Animation(name: "idle", frameCount: 1, fps: 1)

        return BehaviorState(
            phase: .enter,
            position: position,
            animation: AnimationState(animation: animation),
            startTime: context.currentTime,
            duration: 2.0
        )
    }

    private func calculateEndPosition(
        window: ScreenRect,
        edge: ScreenRect.WindowEdge,
        direction: Bool
    ) -> Position {
        let margin: Double = 20

        switch edge {
        case .top:
            // Move horizontally along top edge
            if direction {
                return Position(x: window.maxX - margin, y: window.minY)
            } else {
                return Position(x: window.minX + margin, y: window.minY)
            }

        case .bottom:
            // Move horizontally along bottom edge
            if direction {
                return Position(x: window.maxX - margin, y: window.maxY)
            } else {
                return Position(x: window.minX + margin, y: window.maxY)
            }

        case .left:
            // Move vertically along left edge
            if direction {
                return Position(x: window.minX, y: window.maxY - margin)
            } else {
                return Position(x: window.minX, y: window.minY + margin)
            }

        case .right:
            // Move vertically along right edge
            if direction {
                return Position(x: window.maxX, y: window.maxY - margin)
            } else {
                return Position(x: window.maxX, y: window.minY + margin)
            }
        }
    }

    private func climbAnimation(for edge: ScreenRect.WindowEdge, creature: Creature) -> Animation {
        // Try edge-specific climb animation first
        let edgeName: String
        switch edge {
        case .top: edgeName = "climb-top"
        case .bottom: edgeName = "climb-bottom"
        case .left: edgeName = "climb-left"
        case .right: edgeName = "climb-right"
        }

        if let anim = creature.animation(named: edgeName) {
            return anim
        }

        // Fall back to generic climb
        if let anim = creature.animation(named: "climb") {
            return anim
        }

        // Fall back to walk for horizontal, or idle
        if edge == .top || edge == .bottom {
            if let anim = creature.animation(named: "walk-right") {
                return anim
            }
        }

        // Final fallback to idle
        return creature.animation(named: "idle") ?? Animation(name: "idle", frameCount: 1, fps: 1)
    }
}

// MARK: - Personality Extension

extension Personality {
    /// Speed in pixels per second for climbing behavior
    var climbSpeed: Double {
        switch self {
        case .shy:
            return 40.0        // Very slow, cautious
        case .curious:
            return 70.0        // Moderate pace
        case .mischievous:
            return 100.0       // Quick
        case .chaotic:
            return 130.0       // Fast and erratic
        }
    }
}

